package frc.robot.generated;

import edu.wpi.first.math.geometry.Pose2d;
import edu.wpi.first.math.geometry.Rotation2d;

import java.util.Map;
import java.util.OptionalInt;

/**
 * A class containing the name, start pose, end pose, and total time of every Choreo trajectory.
 * This prevents your code from referencing deleted or misspelled trajectories, and removes the need
 * for JSON parsing to load a trajectory's essential data. DO NOT MODIFY THIS FILE YOURSELF! It is
 * automatically generated by Choreo.
 */
public record ChoreoTraj(
        String name,
        OptionalInt segment,
        double totalTimeSecs,
        Pose2d initialPoseBlue,
        Pose2d endPoseBlue) {
    public static final ChoreoTraj Neutral2 =
            new ChoreoTraj(
                    "Neutral2",
                    OptionalInt.empty(),
                    7.01446,
                    new Pose2d(3.12514, 7.30892, Rotation2d.fromRadians(-1.15368)),
                    new Pose2d(3.12514, 7.30892, Rotation2d.fromRadians(-1.15368)));
    public static final ChoreoTraj NeutralSafe2 =
            new ChoreoTraj(
                    "NeutralSafe2",
                    OptionalInt.empty(),
                    5.89838,
                    new Pose2d(3.12514, 7.30892, Rotation2d.fromRadians(-1.15368)),
                    new Pose2d(3.12514, 7.30892, Rotation2d.fromRadians(-1.15368)));
    public static final ChoreoTraj Neutral1 =
            new ChoreoTraj(
                    "Neutral1",
                    OptionalInt.empty(),
                    6.72998,
                    new Pose2d(4.45, 7.39928, Rotation2d.fromRadians(1.5708)),
                    new Pose2d(3.12514, 7.30892, Rotation2d.fromRadians(-1.15368)));
    public static final ChoreoTraj NeutralSafe1 =
            new ChoreoTraj(
                    "NeutralSafe1",
                    OptionalInt.empty(),
                    5.43834,
                    new Pose2d(4.45, 7.39928, Rotation2d.fromRadians(1.5708)),
                    new Pose2d(3.12514, 7.30892, Rotation2d.fromRadians(-1.15368)));

    /**
     * A map between trajectory names and their corresponding data. This allows for trajectory data
     * to be looked up with strings during runtime.
     */
    public static final Map<String, ChoreoTraj> ALL_TRAJECTORIES =
            Map.ofEntries(
                    Map.entry("Neutral2", Neutral2),
                    Map.entry("NeutralSafe2", NeutralSafe2),
                    Map.entry("Neutral1", Neutral1),
                    Map.entry("NeutralSafe1", NeutralSafe1));

    /**
     * Looks up the ChoreoTraj segment of the given overall ChoreoTraj. WARNING: will raise an
     * exception if not called with a valid segment index.
     */
    public ChoreoTraj segment(int segment) {
        var traj = ChoreoTraj.ALL_TRAJECTORIES.get(this.name + "$" + segment);
        if (traj == null) {
            throw new NullPointerException(
                    "Trajectory " + this.name + " does not have segment #" + segment + ".");
        }
        return traj;
    }
}
